import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Setting Up Aidis","description":"","frontmatter":{},"headers":[],"relativePath":"setup/index.md","filePath":"setup/index.md"}'),i={name:"setup/index.md"};function n(s,e,l,h,c,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="setting-up-aidis" tabindex="-1">Setting Up Aidis <a class="header-anchor" href="#setting-up-aidis" aria-label="Permalink to &quot;Setting Up Aidis&quot;">​</a></h1><p>Aidis is a desktop application for managing your AI agents. It provides a visual interface for everything you&#39;d normally do through the CLI.</p><blockquote><p><strong>Note:</strong> Aidis currently depends on the <a href="https://zeroclawlabs.ai" target="_blank" rel="noreferrer">zeroclaw CLI</a> for agent operations. The zeroclaw binary must be installed and available on your system <code>PATH</code>.</p></blockquote><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ol><li><p><strong>Install zeroclaw CLI</strong> — Run the one-liner installer from the official site:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://zeroclawlabs.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>Or follow the instructions at <a href="https://zeroclawlabs.ai" target="_blank" rel="noreferrer">zeroclawlabs.ai</a>. Source: <a href="https://github.com/zeroclaw-labs/zeroclaw" target="_blank" rel="noreferrer">github.com/zeroclaw-labs/zeroclaw</a>.</p></li><li><p><strong>Node.js</strong> &gt;= 18 and <strong>npm</strong> &gt;= 9</p></li></ol><h2 id="install-run" tabindex="-1">Install &amp; Run <a class="header-anchor" href="#install-run" aria-label="Permalink to &quot;Install &amp; Run&quot;">​</a></h2><p>Download the latest release for your platform from the <a href="https://github.com/nicholasbester/aidis-releases/releases/latest" target="_blank" rel="noreferrer">Aidis Releases page</a>:</p><ul><li><strong>macOS</strong> — Download the <code>.dmg</code> (Apple Silicon or Intel) and drag Aidis to your Applications folder</li><li><strong>Linux</strong> — Download the <code>.AppImage</code>, <code>.deb</code>, or <code>.tar.gz</code></li></ul><p>Then launch Aidis from your Applications menu or via the command line.</p><blockquote><p><strong>Note:</strong> Aidis is source-available under the <a href="https://github.com/nicholasbester/aidis-releases/blob/main/LICENSE" target="_blank" rel="noreferrer">PolyForm Noncommercial License 1.0.0</a>. It is free for personal, hobby, research, educational, and non-profit use. Commercial use requires a separate commercial license — contact <a href="mailto:licensing@aidis.ai" target="_blank" rel="noreferrer">licensing@aidis.ai</a>.</p></blockquote><h2 id="first-launch" tabindex="-1">First Launch <a class="header-anchor" href="#first-launch" aria-label="Permalink to &quot;First Launch&quot;">​</a></h2><p>When you start Aidis for the first time, the <strong>Onboarding Wizard</strong> will walk you through:</p><ol><li><strong>Detect Installation</strong> — Confirms the zeroclaw CLI is installed and shows the binary path</li><li><strong>Provider Setup</strong> — Select your LLM provider (OpenRouter, OpenAI, Anthropic, etc.) and enter your API key</li><li><strong>Channel Setup</strong> — Configure your primary communication channels (Telegram, Discord, Slack, etc.)</li><li><strong>Test Connection</strong> — Send a test message to verify your agent is responding</li></ol><h2 id="what-you-can-do" tabindex="-1">What You Can Do <a class="header-anchor" href="#what-you-can-do" aria-label="Permalink to &quot;What You Can Do&quot;">​</a></h2><h3 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h3><p>Monitor your agent daemon in real-time. Start, stop, and restart the daemon. View streaming logs with search and filtering. Run diagnostics with the built-in doctor and channel health checks.</p><h3 id="agent-workspace" tabindex="-1">Agent Workspace <a class="header-anchor" href="#agent-workspace" aria-label="Permalink to &quot;Agent Workspace&quot;">​</a></h3><p>Shape your agent&#39;s personality and behavior through visual markdown editors:</p><ul><li><strong>Identity</strong> — Name, creature type, vibe, and emoji</li><li><strong>Soul</strong> — Personality traits, values, and communication style</li><li><strong>Agent</strong> — Workflows, tools, and safety rules</li><li><strong>User</strong> — Your context and preferences</li><li><strong>Memory</strong> — Long-term curated memory</li><li><strong>Heartbeat</strong> — Recurring maintenance tasks with interval scheduling</li><li><strong>Tools</strong> — Tool usage guidelines and environment notes</li></ul><p>All workspace editors include AI-assisted content generation.</p><h3 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h3><p>Browse and install skills from the community marketplace. Manage installed skills and install custom skills from any URL.</p><h3 id="chat" tabindex="-1">Chat <a class="header-anchor" href="#chat" aria-label="Permalink to &quot;Chat&quot;">​</a></h3><p>Test your agent with a built-in chat interface featuring real-time message streaming.</p><h3 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h3><p>Edit all 29 sections of the agent configuration:</p><ul><li><strong>General</strong> — Provider, model, temperature</li><li><strong>Channels</strong> — 15+ integrations (Telegram, Discord, Slack, WhatsApp, Matrix, Signal, Email, IRC, and more)</li><li><strong>Model Routes</strong> — Route hints for model and embedding selection</li><li><strong>Scheduler</strong> — Cron job management with interval, time-based, and one-shot scheduling</li><li><strong>Autonomy</strong> — Access levels, blocked commands, allowed domains</li><li><strong>Runtime</strong> — Reasoning, streaming, token limits, timeouts</li><li><strong>Cost</strong> — Budget enforcement with daily and monthly limits</li><li><strong>Observability</strong> — Log levels, tracing, OpenTelemetry export</li><li><strong>Gateway, Memory, Browser, Web Search, Storage, Secrets</strong> — and more</li></ul><h2 id="zeroclaw-cli-documentation" tabindex="-1">zeroclaw CLI Documentation <a class="header-anchor" href="#zeroclaw-cli-documentation" aria-label="Permalink to &quot;zeroclaw CLI Documentation&quot;">​</a></h2><p>For documentation on the zeroclaw CLI (the agent runtime), see the <a href="https://zeroclawlabs.ai" target="_blank" rel="noreferrer">official zeroclaw website</a> or the <a href="https://github.com/zeroclaw-labs/zeroclaw" target="_blank" rel="noreferrer">source repository</a>.</p>',29)])])}const p=a(i,[["render",n]]);export{u as __pageData,p as default};
